export function getPeptideById(id) {
  return PEPTIDES.find(p => p.id === id);
}

export function getPeptidesByGoal(goal) {
  return PEPTIDES.filter(p => Array.isArray(p.goals) && p.goals.includes(goal));
}

export function getPeptidesByCategory(cat) {
  return PEPTIDES.filter(p => p.cat === cat);
}

